# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.parse as parse
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    
    if 'x-enrich-url' in request['headers']:
        enrichmentUrlHeaders = [header for header in request['headers'] 
                                if header['name'].lower() == 'x-enrich-url'][0]
        
        url_to_fetch = parse.unquote(enrichmentUrlHeaders['value'])

        # Fetch data and add to the request headers
        try:
            response = requests.get(url_to_fetch)
            
            if response.status_code == 200:
                new_headers = json.loads(response.text)
                
                for key, value in new_headers.items():
                    request['headers'][key] = [{'key': key, 'value': parse.unquote(str(value))}]
                    
        except Exception as e:
            print("Error while fetching enrichment data from "+ url_to_fetch +" - " + str(e))
    
    return request